using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_ItemIsInCart()
    {
        _cart.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_TotalReflectsAll()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 3, 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantitiesAccumulate()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 2, 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_ZeroQuantity_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", 0, 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", 1, -5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NullSku_ThrowsArgumentException()
    {
        _cart.AddItem(null!, 1, 10.00m);
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_ItemNoLongerInTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_NonExistentItem_ThrowsInvalidOperationException()
    {
        _cart.RemoveItem("SKU-MISSING");
    }

    [TestMethod]
    public void RemoveItem_AllItems_TotalIsZero()
    {
        _cart.AddItem("SKU-001", 2, 15.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsCorrectSum()
    {
        _cart.AddItem("A", 2, 5.50m);
        _cart.AddItem("B", 1, 3.25m);

        Assert.AreEqual(14.25m, _cart.CalculateTotal());
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();
        Assert.IsTrue(total < 100.00m, $"Expected total < 100, but was {total}");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        _cart.ApplyCoupon("BOGUS");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_NullCode_ThrowsArgumentException()
    {
        _cart.ApplyCoupon(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void ApplyCoupon_AppliedTwice_ThrowsInvalidOperationException()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE10");
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }
}

